export function LauncherCategoryIcon({
  size = 110,
  className,
  type,
}: {
  size?: number;
  className?: string;
  type: "session" | "job" | "app";
}) {
  const iconMap = {
    session: SessionIconSvg,
    job: JobIconSvg,
    app: AppIconSvg,
  };

  const Icon = iconMap[type];

  return (
    <Icon
      className={cx("bi", className)}
      style={{ width: size, height: size }}
    />
  );
}
